package genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_manufacturer.service.VehicleManufacturerService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/manufacturers") public class VehicleManufacturerController { private final VehicleManufacturerService service; public VehicleManufacturerController(VehicleManufacturerService service){this.service=service;} @GetMapping public List<VehicleManufacturerResponse> list(@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(), filters, Set.of()); } @GetMapping("/{id}") public VehicleManufacturerResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleManufacturerResponse create(@RequestBody VehicleManufacturerUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleManufacturerResponse update(@PathVariable UUID id,@RequestBody VehicleManufacturerUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
